using System.ComponentModel;
using System.Text.Json;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides web search functionality for the research agent.
/// In production, replace the simulated results with a real search API
/// (e.g., Bing Search API, Google Custom Search).
/// </summary>
public sealed class WebSearchTool
{
    private static readonly HttpClient s_httpClient = new()
    {
        Timeout = TimeSpan.FromSeconds(15),
    };

    [Description("Search the web for information on a given query. Returns a list of search results with titles, URLs, and snippets.")]
    public static async Task<IReadOnlyList<SearchResult>> SearchWebAsync(
        [Description("The search query string")] string query,
        [Description("Maximum number of results to return (1-10)")] int maxResults = 5,
        CancellationToken cancellationToken = default)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(query);
        maxResults = Math.Clamp(maxResults, 1, 10);

        // Try a real search via DuckDuckGo Instant Answer API (no key required)
        try
        {
            var encodedQuery = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encodedQuery}&format=json&no_html=1&skip_disambig=1";

            var response = await s_httpClient.GetStringAsync(url, cancellationToken);
            var doc = JsonDocument.Parse(response);
            var results = new List<SearchResult>();

            // Extract abstract if available
            var abstractText = doc.RootElement.GetProperty("AbstractText").GetString();
            var abstractSource = doc.RootElement.GetProperty("AbstractSource").GetString();
            var abstractUrl = doc.RootElement.GetProperty("AbstractURL").GetString();

            if (!string.IsNullOrWhiteSpace(abstractText))
            {
                results.Add(new SearchResult(
                    $"{abstractSource}: {query}",
                    abstractUrl ?? "",
                    abstractText));
            }

            // Extract related topics
            if (doc.RootElement.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var topic in topics.EnumerateArray())
                {
                    if (results.Count >= maxResults)
                        break;

                    var text = topic.TryGetProperty("Text", out var t) ? t.GetString() : null;
                    var firstUrl = topic.TryGetProperty("FirstURL", out var u) ? u.GetString() : null;

                    if (!string.IsNullOrWhiteSpace(text))
                    {
                        results.Add(new SearchResult(
                            text.Length > 80 ? text[..80] + "..." : text,
                            firstUrl ?? "",
                            text));
                    }
                }
            }

            if (results.Count > 0)
                return results;
        }
        catch
        {
            // Fall through to simulated results
        }

        // Fallback: return simulated results so the agent still works without network
        return GenerateSimulatedResults(query, maxResults);
    }

    private static List<SearchResult> GenerateSimulatedResults(string query, int maxResults)
    {
        var results = new List<SearchResult>
        {
            new($"Overview of {query} - Wikipedia",
                $"https://en.wikipedia.org/wiki/{Uri.EscapeDataString(query)}",
                $"A comprehensive overview of {query}, covering history, key concepts, and recent developments."),
            new($"Latest research on {query} - Nature",
                $"https://nature.com/articles/{Uri.EscapeDataString(query)}",
                $"Recent peer-reviewed research findings related to {query}, including methodology and conclusions."),
            new($"{query}: A practical guide - MIT Technology Review",
                "https://technologyreview.com/topic/" + Uri.EscapeDataString(query),
                $"An accessible guide explaining {query} fundamentals, real-world applications, and future outlook."),
            new($"Industry analysis: {query} trends 2026",
                "https://reuters.com/technology/" + Uri.EscapeDataString(query),
                $"Market analysis and industry trends related to {query}, with expert commentary and data."),
            new($"{query} explained - Stanford AI Lab",
                "https://ai.stanford.edu/research/" + Uri.EscapeDataString(query),
                $"Technical deep-dive into {query} from Stanford researchers, covering theory and applications."),
        };

        return results.Take(maxResults).ToList();
    }
}

public sealed record SearchResult(
    [property: Description("Title of the search result")] string Title,
    [property: Description("URL of the search result")] string Url,
    [property: Description("Brief snippet or summary from the page")] string Snippet);

using System.ComponentModel;
using System.Text;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides note-taking capabilities so the agent can collect, organize,
/// and retrieve findings during its research session.
/// </summary>
public sealed class NoteTakingTool
{
    private readonly List<Note> _notes = [];
    private readonly Lock _lock = new();

    [Description("Save a research note with a category tag. Use this to record important findings from web searches.")]
    public string AddNote(
        [Description("Category for the note (e.g., 'key-finding', 'definition', 'statistic', 'quote', 'source')")] string category,
        [Description("The content of the note")] string content,
        [Description("Optional source URL where this information was found")] string? sourceUrl = null)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(category);
        ArgumentException.ThrowIfNullOrWhiteSpace(content);

        lock (_lock)
        {
            var note = new Note(
                Id: _notes.Count + 1,
                Category: category.Trim().ToLowerInvariant(),
                Content: content.Trim(),
                SourceUrl: sourceUrl?.Trim(),
                Timestamp: DateTimeOffset.UtcNow);

            _notes.Add(note);
            return $"Note #{note.Id} saved under '{note.Category}'.";
        }
    }

    [Description("Retrieve all saved notes, optionally filtered by category.")]
    public IReadOnlyList<Note> GetNotes(
        [Description("Optional category filter. Leave null to get all notes.")] string? category = null)
    {
        lock (_lock)
        {
            if (string.IsNullOrWhiteSpace(category))
                return _notes.ToList();

            var normalized = category.Trim().ToLowerInvariant();
            return _notes.Where(n => n.Category == normalized).ToList();
        }
    }

    [Description("Get a formatted summary of all collected notes grouped by category.")]
    public string GetNotesSummary()
    {
        lock (_lock)
        {
            if (_notes.Count == 0)
                return "No notes have been collected yet.";

            var sb = new StringBuilder();
            sb.AppendLine($"=== Research Notes ({_notes.Count} total) ===");

            foreach (var group in _notes.GroupBy(n => n.Category).OrderBy(g => g.Key))
            {
                sb.AppendLine();
                sb.AppendLine($"[{group.Key.ToUpperInvariant()}] ({group.Count()} notes)");

                foreach (var note in group)
                {
                    sb.AppendLine($"  #{note.Id}: {note.Content}");
                    if (!string.IsNullOrWhiteSpace(note.SourceUrl))
                        sb.AppendLine($"       Source: {note.SourceUrl}");
                }
            }

            return sb.ToString();
        }
    }
}

public sealed record Note(
    [property: Description("Unique note identifier")] int Id,
    [property: Description("Category tag")] string Category,
    [property: Description("Note content")] string Content,
    [property: Description("Source URL, if any")] string? SourceUrl,
    [property: Description("When the note was created")] DateTimeOffset Timestamp);

